static void rmt_to_manchester_decode(rmt_symbol_t *symbols, size_t count) {
    uint8_t half_bits[MAX_RMT_SYMBOLS * 2];
    int hb_count = 0;
    for (size_t i = 0; i < count; i++) {
        int d0 = symbols[i].duration0; 
        int v0 = symbols[i].level0;
        int d1 = symbols[i].duration1;
        int v1 = symbols[i].level1;

        if (d0 < 8) continue; // Noise filter < 2us
        int num_hb0 = (d0 + 8) / 16;
        if (num_hb0 > 4) num_hb0 = 4; // Cap long pulses
        for(int j=0; j<num_hb0 && hb_count < sizeof(half_bits); j++) half_bits[hb_count++] = v0;

        if (d1 < 8) continue;
        int num_hb1 = (d1 + 8) / 16;
        if (num_hb1 > 4) num_hb1 = 4;
        for(int j=0; j<num_hb1 && hb_count < sizeof(half_bits); j++) half_bits[hb_count++] = v1;
    }

    uint32_t current_byte = 0;
    int bit_count = 0;
    uint8_t payload[64];
    uint8_t payload_len = 0;
    bool synced = false;

    int sync_idx = -1;
    uint32_t pattern = 0;
    for (int i = 0; i < hb_count; i++) {
        pattern = (pattern << 1) | half_bits[i];
        // EnOcean Preamble 0xAA (10101010) + Sync 0xAD (10101101)
        // If 125kbps raw bits: 1100110011001100 1100110011110011 (Preamble byte + Sync byte)
        // We look for 0xCCF3 (The raw sync byte bits)
        if ((pattern & 0xFFFF) == 0xCCF3) { 
            sync_idx = i + 1;
            synced = true;
            break;
        }
    }

    if (synced && sync_idx != -1) {
        for (int i = sync_idx; i < hb_count - 1; i += 2) {
            uint8_t hb1 = half_bits[i];
            uint8_t hb2 = half_bits[i+1];
            int decoded_bit = -1;
            // Manchester EnOcean: 1 -> 10, 0 -> 01
            if (hb1 == 1 && hb2 == 0) decoded_bit = 1;
            else if (hb1 == 0 && hb2 == 1) decoded_bit = 0;
            else {
                // Try resync
                i--; continue;
            }

            current_byte = (current_byte << 1) | decoded_bit;
            bit_count++;
            if (bit_count == 8) {
                if (payload_len < sizeof(payload)) payload[payload_len++] = current_byte;
                bit_count = 0;
            }
        }
    }

    if (payload_len > 0) {
        esp3_send_radio_erp1(payload, payload_len, -70);
    }
}

