static rmt_symbol_word_t rmt_rx_buffer[1024];

// Problem: Constant reboots with SW_CPU reset on ESP32-C6.
// The device is connected to CC1101 GDO0 (Data) and GDO2 (Carrier Sense).
// Bitrate is 125kbps OOK.

response.result:
Experten-Analyse (gemini-pro-latest):
Als Senior Expert Advisor analysiere ich dein Problem auf Architektur- und Treiberebene. 

Das Symptom, das du beschreibst (**SW_CPU Resets / Watchdog Reboots in Kombination mit abbrechendem nativem USB-CDC**), ist ein absolut klassisches Verhalten, wenn man OOK-Signale (On-Off Keying) mit dem RMT-Peripherieblock ohne korrekte Filterung oder Gating empfängt.

Hier ist die fundierte Analyse und die Lösung für dein Problem.

### Die Root Cause Analyse (Warum dein ESP32-C6 abstürzt)

Das Problem liegt bei deiner Frage 3: **OOK Noise und Interrupt-Stürme.**
Ein CC1101, der auf OOK ohne anliegendes Trägersignal (Carrier) konfiguriert ist, gibt auf GDO0 reines, hochfrequentes "Weißes Rauschen" aus. 
Der RMT-Block des ESP32 ist eigentlich für Infrarot-Signale (langsame, seltene Pulse) gedacht. Wenn du nun 125 kHz Rauschen auf den RMT gibst:
1. Der RMT-Block sampelt dieses Rauschen und füllt sein internes RAM (bzw. den DMA-Puffer) in Bruchteilen einer Millisekunde.
2. Der RMT feuert kontinuierlich Buffer-Full- bzw. DMA-Done-Interrupts ab (Tausende pro Sekunde).
3. **CPU Starvation:** Die CPU ist nur noch im Interrupt-Kontext gefangen (Interrupt Storm). Die FreeRTOS Idle-Task und das USB-CDC-Polling kommen nicht mehr zum Zug.
4. Der Interrupt Watchdog (IWDT) oder Task Watchdog (TWDT) schlägt zu und löst einen `SW_CPU` Reset aus. Der USB-Port friert vorher ein.

---

### Antworten auf deine spezifischen Fragen

#### 1. DMA-Nutzung und Puffer-Allokation
**Ja, du musst zwingend DMA nutzen** bei 125 kbps. Ein statisches Array (`static rmt_symbol_word_t rmt_rx_buffer[1024];`) ist jedoch **falsch für DMA**, da ESP32-C6 DMA-Puffer spezielle Alignment-Anforderungen haben (im internen SRAM, cache-aligned). Wenn du ein statisches Array nutzt, das zufällig die Cache-Line-Boundaries verletzt, stürzt der DMA-Controller ab.
*Lösung:* Nutze `heap_caps_calloc` mit `MALLOC_CAP_DMA | MALLOC_CAP_INTERNAL`.

#### 2. `mem_block_symbols` und Puffergröße für EnOcean ERP1
* **`mem_block_symbols`:** Der ESP32-C6 hat Hardware-seitig **nur 48 Words RAM pro RMT-Kanal**. Dein Wert `64` ist zu hoch und führt intern zu Fehlern. Setze ihn auf `48`.
* **Puffergröße:** ERP1 hat max ~42 Bytes Payload + Preamble/Sync. Manchester-codiert sind das max ~800 Symbole (RMT-Flanken). Ein DMA-Puffer von **1024 Symbolen** ist perfekt dimensioniert.

#### 3. Frequenz der Interrupts und Watchdog-Reset
Wie oben beschrieben: Ja. Das ist der Hauptauslöser. Du darfst den RMT-RX **niemals** dauerhaft laufen lassen, wenn GDO0 Rauschen ausgibt.

#### 4. Die Lösung: Carrier Sense (CS) Gating
Du schreibst, du hast GDO2 als **Carrier Sense (CS)** konfiguriert. Das ist der Schlüssel!
Du darfst den RMT (`rmt_enable` und `rmt_receive`) **nur dann aktivieren**, wenn der CC1101 via GDO2 meldet, dass ein valider Träger (Signal) in der Luft ist. Fällt CS ab, musst du den RMT sofort deaktivieren (`rmt_disable`).

---

### Robuste Implementierung (Code-Lösung)

Hier ist die Best-Practice-Implementierung für den ESP-IDF v5 RMT-Treiber.

#### 1. Initialisierung des RMT

```c
#include "driver/rmt_rx.h"
#include "esp_heap_caps.h"

// Globale Variablen
rmt_channel_handle_t rx_channel = NULL;
rmt_symbol_word_t *rmt_rx_buffer = NULL;
SemaphoreHandle_t rmt_done_sem = NULL;

#define RMT_RX_BUFFER_SIZE 1024
#define RMT_RESOLUTION_HZ  1000000 // 1 MHz = 1us Auflösung (perfekt für 8us Pulse bei 125kbps)

// Callback, wenn RMT fertig ist (Idle Timeout oder Buffer voll)
static bool IRAM_ATTR rmt_rx_done_callback(rmt_channel_handle_t channel, const rmt_rx_done_event_data_t *edata, void *user_data) {
    BaseType_t high_task_wakeup = pdFALSE;
    xSemaphoreGiveFromISR(rmt_done_sem, &high_task_wakeup);
    return high_task_wakeup == pdTRUE;
}

void radio_rmt_rx_init(void) {
    rmt_done_sem = xSemaphoreCreateBinary();

    // 1. DMA-fähigen Speicher allokieren (Zwingend für ESP32-C6 DMA!)
    rmt_rx_buffer = (rmt_symbol_word_t *)heap_caps_calloc(
        RMT_RX_BUFFER_SIZE, 
        sizeof(rmt_symbol_word_t), 
        MALLOC_CAP_DMA | MALLOC_CAP_INTERNAL | MALLOC_CAP_8BIT
    );
    ESP_ERROR_CHECK(rmt_rx_buffer == NULL ? ESP_ERR_NO_MEM : ESP_OK);

    // 2. RMT Konfiguration
    rmt_rx_channel_config_t rx_chan_config = {
        .clk_src = RMT_CLK_SRC_DEFAULT,
        .resolution_hz = RMT_RESOLUTION_HZ,
        .mem_block_symbols = 48, // ESP32-C6 hat max 48 per Kanal! (Nicht 64)
        .gpio_num = PIN_GDO0,
        .flags.invert_in = false,
        .flags.with_dma = true
    };
    ESP_ERROR_CHECK(rmt_new_rx_channel(&rx_chan_config, &rx_channel));

    // 3. Callback registrieren
    rmt_rx_event_callbacks_t cbs = {
        .on_recv_done = rmt_rx_done_callback,
    };
    ESP_ERROR_CHECK(rmt_rx_register_event_callbacks(rx_channel, &cbs, NULL));

    // RMT bleibt initial deaktiviert! Aktivierung erfolgt nur über Carrier Sense.
}
```

#### 2. Carrier Sense Interrupt Setup (GDO2)
Richte GDO2 (Carrier Sense) so ein, dass er einen Interrupt auslöst, wenn das Signal HIGH wird.

```c
SemaphoreHandle_t carrier_sense_sem = NULL;

static void IRAM_ATTR gdo2_cs_isr_handler(void* arg) {
    // Wenn GDO2 (CS) auf HIGH geht, wecke die RX-Task
    BaseType_t high_task_wakeup = pdFALSE;
    xSemaphoreGiveFromISR(carrier_sense_sem, &high_task_wakeup);
    portYIELD_FROM_ISR(high_task_wakeup);
}

void init_cs_interrupt(void) {
    carrier_sense_sem = xSemaphoreCreateBinary();

    gpio_config_t io_conf = {
        .intr_type = GPIO_INTR_POSEDGE, // Trigger bei steigender Flanke (Carrier erkannt)
        .pin_bit_mask = (1ULL << PIN_GDO2),
        .mode = GPIO_MODE_INPUT,
        .pull_down_en = 0,
        .pull_up_en = 0
    };
    gpio_config(&io_conf);
    gpio_install_isr_service(0);
    gpio_isr_handler_add(PIN_GDO2, gdo2_cs_isr_handler, NULL);
}
```

#### 3. Die stabile Empfangs-Schleife (FreeRTOS Task)

```c
void radio_rx_task(void *arg) {
    while (1) {
        // 1. Warte bis ein Trägersignal (Carrier Sense) erkannt wird
        if (xSemaphoreTake(carrier_sense_sem, portMAX_DELAY) == pdTRUE) {

            // 2. RMT jetzt erst einschalten
            ESP_ERROR_CHECK(rmt_enable(rx_channel));

            // Bei 125kbps dauert 1 Bit 8us. 
            // Manchester Encode: max. 2 Bits lang gleicher Pegel = 16us.
            // Timeout-Bedingung: Wenn für 40us keine Flanke mehr kommt, ist das Paket vorbei.
            rmt_receive_config_t rx_config = {
                .signal_range_min_ns = 1000,   // Glitch-Filterung: Flanken < 1us ignorieren
                .signal_range_max_ns = 40000,  // Idle Threshold: 40us Ruhe bedeutet Paketende
            };

            // 3. Empfang starten
            ESP_ERROR_CHECK(rmt_receive(rx_channel, rmt_rx_buffer, RMT_RX_BUFFER_SIZE * sizeof(rmt_symbol_word_t), &rx_config));

            // 4. Warte auf Paketende oder Timeout (max 20ms bei 125kbps für ein ERP1 Paket)
            // Wenn der Carrier Sense ein False-Positive war, läuft dieser Timeout ab, 
            // ohne die CPU zu blockieren.
            if (xSemaphoreTake(rmt_done_sem, pdMS_TO_TICKS(20)) == pdTRUE) {
                // PAKET EMPFANGEN! 
                // Hier Logik für Manchester-Decoding aufrufen
                process_erp1_packet(rmt_rx_buffer); 
            }

            // 5. RMT sofort wieder ausschalten, um Interrupt-Storm durch Rauschen zu verhindern
            ESP_ERROR_CHECK(rmt_disable(rx_channel));

            // Wichtig: RX Puffer/Hardware zurücksetzen falls nötig, macht ESP-IDF idR intern beim disable/enable
        }
    }
}
```

### Zusammenfassung der Architektur-Gewinne:
1. **Kein Interrupt-Storm mehr:** Die CPU entspannt sich. Die USB-CDC Verbindung auf dem ESP32-C6 bleibt extrem stabil, da sie nicht mehr durch RMT-Interrupts verhungert (`SW_CPU` Reset ist behoben).
2. **Sauberer DMA:** Durch `MALLOC_CAP_DMA` läuft der Transfer ohne Bus-Fehler am Cache vorbei direkt in den RAM.
3. **Perfektes Timing:** Mit dem `signal_range_max_ns` von 40µs (5 Bit-Längen bei 125kbps) erkennt der Hardware-Block exakt das Ende der Manchester-Übertragung und beendet den DMA-Transfer völlig selbstständig.

